import { pipe } from "fp-ts/function";
import * as TE from "fp-ts/TaskEither";

type RefreshError = { readonly _tag: "RefreshError"; readonly cause: string };
const refreshError = (cause: string): RefreshError => ({ _tag: "RefreshError", cause });

type Token = { readonly access: string; readonly expiresAt: number };

declare const callOAuth: (refreshToken: string) => Promise<Token>;

const refreshOnce = (rt: string): TE.TaskEither<RefreshError, Token> =>
  TE.tryCatch(
    () => callOAuth(rt),
    (u) => refreshError(u instanceof Error ? u.message : String(u)),
  );

const retryN = <E, A>(te: TE.TaskEither<E, A>, n: number): TE.TaskEither<E, A> =>
  n <= 0 ? te : pipe(te, TE.orElse(() => retryN(te, n - 1)));

export const refreshWithRetry = (rt: string) =>
  pipe(
    retryN(refreshOnce(rt), 3),
    TE.chain((tok) =>
      tok.expiresAt > Date.now() ? TE.right(tok) : TE.left(refreshError("expired")),
    ),
    TE.map((tok) => tok.access),
  );
