import { Effect, Queue, Fiber, Data, pipe } from "effect";

type OrderEvent =
  | { readonly _tag: "Placed"; readonly id: string }
  | { readonly _tag: "Paid"; readonly id: string }
  | { readonly _tag: "Shipped"; readonly id: string };

class DispatchError extends Data.TaggedError("DispatchError")<{ readonly cause: string }> {}

const handle = (e: OrderEvent): Effect.Effect<string, DispatchError> => {
  switch (e._tag) {
    case "Placed":
      return Effect.succeed(`placed ${e.id}`);
    case "Paid":
      return Effect.succeed(`paid ${e.id}`);
    case "Shipped":
      return Effect.succeed(`shipped ${e.id}`);
  }
};

export const workflow = Effect.gen(function* () {
  const q = yield* Queue.unbounded<OrderEvent>();
  const consumer = yield* Effect.fork(
    Effect.gen(function* () {
      while (true) {
        const evt = yield* Queue.take(q);
        yield* pipe(handle(evt), Effect.tap((s) => Effect.sync(() => void s)));
      }
    }),
  );
  yield* Queue.offer(q, { _tag: "Placed", id: "o1" });
  yield* Queue.offer(q, { _tag: "Paid", id: "o1" });
  yield* Queue.offer(q, { _tag: "Shipped", id: "o1" });
  yield* Effect.sleep("10 millis");
  yield* Fiber.interrupt(consumer);
  return "done";
});
