import { Effect, Data, pipe } from "effect";

class ParseError extends Data.TaggedError("ParseError")<{ readonly at: number }> {}

interface Parsed { readonly tokens: ReadonlyArray<string> }
interface Hit { readonly id: string; readonly score: number }

const parse = (raw: string): Effect.Effect<Parsed, ParseError> =>
  raw.length === 0 ? Effect.fail(new ParseError({ at: 0 })) : Effect.succeed({ tokens: raw.split(/\s+/) });

const normalize = (p: Parsed): Effect.Effect<Parsed> =>
  Effect.succeed({ tokens: p.tokens.map((t) => t.toLowerCase()) });

const execute = (p: Parsed): Effect.Effect<ReadonlyArray<Hit>> =>
  Effect.succeed(p.tokens.map((t, i) => ({ id: `doc:${t}`, score: 1 / (i + 1) })));

const rank = (hits: ReadonlyArray<Hit>): Effect.Effect<ReadonlyArray<Hit>> =>
  Effect.succeed([...hits].sort((a, b) => b.score - a.score));

export const search = (raw: string) =>
  Effect.gen(function* () {
    const parsed = yield* parse(raw);
    const normalized = yield* normalize(parsed);
    const rawHits = yield* execute(normalized);
    const ranked = yield* rank(rawHits);
    return ranked;
  });

export const program = pipe(search("Alpha Beta"), Effect.map((hs) => hs.length));
