import { pipe } from "fp-ts/function";
import * as E from "fp-ts/Either";
import * as RNEA from "fp-ts/ReadonlyNonEmptyArray";

type FieldError = { readonly field: string; readonly msg: string };
type Errors = RNEA.ReadonlyNonEmptyArray<FieldError>;
type Input = { readonly email: string; readonly password: string; readonly age: number };
type Valid = { readonly email: string; readonly password: string; readonly age: number };

const checkEmail = (s: string): E.Either<FieldError, string> =>
  s.includes("@") ? E.right(s) : E.left({ field: "email", msg: "bad email" });
const checkPw = (s: string): E.Either<FieldError, string> =>
  s.length >= 8 ? E.right(s) : E.left({ field: "password", msg: "too short" });
const checkAge = (n: number): E.Either<FieldError, number> =>
  n >= 13 ? E.right(n) : E.left({ field: "age", msg: "too young" });

const collect = <A>(e: E.Either<FieldError, A>): ReadonlyArray<FieldError> =>
  E.isLeft(e) ? [e.left] : [];

export const validate = (i: Input): E.Either<Errors, Valid> => {
  const e1 = checkEmail(i.email);
  const e2 = checkPw(i.password);
  const e3 = checkAge(i.age);
  const errs = [...collect(e1), ...collect(e2), ...collect(e3)];
  if (RNEA.isNonEmpty(errs)) return E.left(errs);
  return pipe(
    E.right<Errors, Valid>({ email: i.email, password: i.password, age: i.age }),
  );
};
