import { pipe } from "fp-ts/function";
import * as E from "fp-ts/Either";

type ParseErr = { readonly _tag: "ParseErr"; readonly raw: string };
type NonPositive = { readonly _tag: "NonPositive"; readonly value: number };
type AppErr = { readonly _tag: "AppErr"; readonly msg: string };

const parseNum = (s: string): E.Either<ParseErr, number> => {
  const n = Number(s);
  return Number.isFinite(n) ? E.right(n) : E.left({ _tag: "ParseErr", raw: s });
};

const ensurePositive = (n: number): E.Either<NonPositive, number> =>
  n > 0 ? E.right(n) : E.left({ _tag: "NonPositive", value: n });

export const reciprocal = (raw: string): string =>
  pipe(
    parseNum(raw),
    E.chainW(ensurePositive),
    E.map((x) => 1 / x),
    E.mapLeft((e): AppErr => ({ _tag: "AppErr", msg: JSON.stringify(e) })),
    E.match(
      (err) => `err:${err.msg}`,
      (v) => `ok:${v}`,
    ),
  );
