  /^\d{5}$/.test(s) ? E.right(s) : E.left({ field: "zip", msg: "bad" });

const errs = <A>(e: E.Either<Err, A>): ReadonlyArray<Err> => (E.isLeft(e) ? [e.left] : []);

export const validate = (i: In): E.Either<Errs, In> => {
  const all = [...errs(nameOk(i.name)), ...errs(emailOk(i.email)), ...errs(zipOk(i.zip))];
  return RNEA.isNonEmpty(all) ? E.left(all) : pipe(E.right<Errs, In>(i));
};
