import { Effect, Data, pipe } from "effect";

class ParseFail extends Data.TaggedError("ParseFail")<{ readonly raw: string }> {}

type Parsed = { readonly tokens: ReadonlyArray<string> };
type Hit = { readonly id: string; readonly score: number };

const parse = (raw: string): Effect.Effect<Parsed, ParseFail> =>
  raw.trim().length === 0 ? Effect.fail(new ParseFail({ raw })) : Effect.succeed({ tokens: raw.split(/\s+/) });

const normalize = (p: Parsed): Parsed => ({ tokens: p.tokens.map((t) => t.toLowerCase()) });

const execute = (p: Parsed): Effect.Effect<ReadonlyArray<Hit>> =>
  Effect.succeed(p.tokens.map((t, i) => ({ id: t, score: 1 / (i + 1) })));

const rank = (h: ReadonlyArray<Hit>): ReadonlyArray<Hit> =>
  [...h].sort((a, b) => b.score - a.score);

export const search = (raw: string) =>
  Effect.gen(function* () {
    const parsed = yield* parse(raw);
    const normalized = normalize(parsed);
    const hits = yield* execute(normalized);
    return rank(hits);
  });

export const program = pipe(search("Foo Bar"), Effect.map((r) => r.length));
