import * as TE from "fp-ts/TaskEither";

class RefreshErr {
  readonly _tag = "RefreshErr" as const;
  constructor(readonly msg: string) {}
}

type Token = { readonly access: string; readonly expiresAt: number };
declare const api: { readonly refresh: (rt: string) => Promise<Token> };

const call = (rt: string): TE.TaskEither<RefreshErr, Token> =>
  TE.tryCatch(
    () => api.refresh(rt),
    (u) => new RefreshErr(u instanceof Error ? u.message : String(u)),
  );

