  t.expiresAt > Date.now() ? TE.right(t) : TE.left(new RefreshErr("expired"));

export const refresh = (rt: string) =>
  pipe(
    call(rt),
    TE.chain(ensureFresh),
    TE.map((t) => t.access),
  );
